mapper.select:
SELECT sc.symbol FROM stock_sec_company sc LEFT JOIN ( SELECT symbol, MAX(fetched_at) AS latest_fetched_at FROM stock_sec_fact GROUP BY symbol ) f ON f.symbol = sc.symbol WHERE sc.symbol IN
#{symbol}
AND ( f.latest_fetched_at IS NULL OR f.latest_fetched_at < TIMESTAMPADD(HOUR, -#{cacheHours}, CURRENT_TIMESTAMP) ) ORDER BY sc.symbol LIMIT #{limit}
